<#Connet To Azure AD#>Connect-AzureAD<#Imports users from CSP into existing UserGroup.#>Import-CSv -Path "C:\Temp\2021-12-15_GetAzureADStaleGuestAccounts (185MaxInactiveTimec-v2).csv" | ForEach {$ObjectID=$_.ObjectIDAdd-AzureADGroupMember -ObjectId "d0a476c1-3c90-4454-b8e9-e9e606685de7" -RefObjectId "$ObjectID"}<#Lists the users from the User Group and deletes the users. #>$GroupID = "Group Obect ID e.g. d0a476c1-3c90-4454-b8e9-e9e60668532f"Get-AzureADGroupMember -ObjectId "$GroupID" | Select-Object -First 1000 | ForEach {$ObjectID=$_.ObjectIDRemove-AzureADUser -ObjectId $ObjectID -Verbose} -Verbose